: 8, "fit_reason": "Individual support-raised campus staffer with personal giving page and defined donor base.", "source_query": "hunter:campus-ministry", "meta": {"h": "campus-ministry", "src": "https://www.georgiaintervarsity.org/clement", "import_source": "import_batch_3.sql"}}, {"org_name": "Christian Abercrombie (InterVarsity Christian Fellowship - Georgia)", "org_type": "individual", "website": "georgiaintervarsity.org/christian", "city": null, "state": null, "summary": "Recent GSW grad now serving on IV staff at his alma mater, with personal page linked from the Georgia donate page. | Field: Georgia Southwestern State University | Comms: Personal staff/giving page live on georgiaintervarsity.org (2026)", "fit_score": 8, "fit_reason": "Young alum-turned-staff raising personal support \u2014 prime early-career, tech-forward DonorSend user.", "source_query": "hunter:campus-ministry", "meta": {"h": "campus-ministry", "src": "https://www.georgiaintervarsity.org/christian", "import_source": "import_batch_3.sql"}}, {"org_name": "Lee Lo (InterVarsity Christian Fellowship - Georgia)", "org_type": "individual", "website": "georgiaintervarsity.org/lee", "city": null, "state": null, "summary": "InterVarsity Georgia area administrator with a personal page on the state donate hub. | Field: Georgia area (administration) | Comms: Personal staff/giving page live on georgiaintervarsity.org (2026)", "fit_score": 6, "fit_reason": "Support-raised IV staffer with individual donation page, though in an admin rather than frontline campus role.", "source_query": "hunter:campus-ministry", "meta": {"h": "campus-ministry", "src": "https://www.georgiaintervarsity.org/lee", "import_source": "import_batch_3.sql"}}]'::jsonb)
  as x(org_name text, org_type text, website text, city text, state text,
       summary text, fit_score int, fit_reason text, source_query text, meta jsonb)),
-- Count how many existing rows (queue + pipeline) share each URL.
-- A URL on exactly one row is a person-specific page safe to dedup
-- against; a URL shared by many is a roster/platform page and must
-- NOT cause a skip, or we'd drop distinct people who list it.
existing_sites as (
  select site, count(*) as n from (
    select rtrim(lower(regexp_replace(website, '^https?://(www\.)?', '', 'i')), '/') as site
      from sales.scout_candidates where website is not null and btrim(website) <> ''
    union all
    select rtrim(lower(regexp_replace(website, '^https?://(www\.)?', '', 'i')), '/') as site
      from sales.leads where website is not null and btrim(website) <> ''
  ) w group by site)
insert into sales.scout_candidates
  (org_name, org_type, website, city, state, summary,
   fit_score, fit_reason, source_query, status, meta)
select s.org_name, s.org_type, s.website, s.city, s.state, s.summary,
       s.fit_score, s.fit_reason, s.source_query, 'pending', coalesce(s.meta, '{}'::jsonb)
from src s
where not exists (select 1 from sales.scout_candidates c
                  where lower(trim(c.org_name)) = lower(trim(s.org_name)))
  and not exists (select 1 from sales.leads l
                  where lower(trim(l.org_name)) = lower(trim(s.org_name)))
  and not exists (select 1 from existing_sites es
                  where s.website is not null and btrim(s.website) <> ''
                    and es.n = 1
                    and es.site = rtrim(lower(regexp_replace(s.website, '^https?://(www\.)?', '', 'i')), '/'));